package com.google.gson.internal.bind;
import static org.mockito.Mockito.*;
import static org.junit.jupiter.api.Assertions.*;

import com.google.gson.Gson;
import com.google.gson.TypeAdapter;
import com.google.gson.reflect.TypeToken;
import com.google.gson.internal.bind.ReflectiveTypeAdapterFactory.Adapter;
import com.google.gson.internal.bind.TypeAdapterRuntimeTypeWrapper;
import com.google.gson.stream.JsonWriter;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;
import org.mockito.Mock;
import org.mockito.MockitoAnnotations;

import java.io.IOException;
import java.lang.reflect.Type;

class TypeAdapterRuntimeTypeWrapperTest {

  @Mock Gson mockGson;
  @Mock TypeAdapter<Object> mockDelegateAdapter;
  @Mock TypeAdapter<Object> mockRuntimeTypeAdapter;
  @Mock JsonWriter mockJsonWriter;

  TypeAdapterRuntimeTypeWrapper<Object> wrapper;
  Type declaredType = Object.class;

  @BeforeEach
  void setUp() {
    MockitoAnnotations.openMocks(this);
    wrapper = new TypeAdapterRuntimeTypeWrapper<>(mockGson, mockDelegateAdapter, declaredType);
  }

  @Test
  void write_runtimeTypeSameAsDeclaredType_usesDelegateWrite() throws IOException {
    Object value = new Object();

    // Spy the static method getRuntimeTypeIfMoreSpecific to return the same declared type
    // Since getRuntimeTypeIfMoreSpecific is private static, use reflection to override it
    // But easier is to pass value whose runtime type is declaredType to produce same result

    // Setup Gson.getAdapter to not be called (since runtimeType == declaredType)
    // So no interaction needed with mockGson.getAdapter

    wrapper.write(mockJsonWriter, value);

    verify(mockDelegateAdapter).write(mockJsonWriter, value);
    verifyNoMoreInteractions(mockGson);
  }

  @Test
  void write_runtimeTypeDifferentAndRuntimeAdapterNotReflective_usesRuntimeAdapter() throws IOException {
    Object value = "string"; // runtimeType = String.class, declaredType = Object.class

    Type runtimeType = String.class;

    // Setup mockGson.getAdapter to return a runtimeTypeAdapter which is NOT instance of ReflectiveTypeAdapterFactory.Adapter
    when(mockGson.getAdapter(TypeToken.get(runtimeType))).thenReturn(mockRuntimeTypeAdapter);
    // Make runtimeTypeAdapter NOT instance of Adapter
    // mockRuntimeTypeAdapter is a mock, so by default false for instanceof Adapter

    // Use a wrapper with declaredType Object.class
    wrapper = new TypeAdapterRuntimeTypeWrapper<>(mockGson, mockDelegateAdapter, declaredType);

    wrapper.write(mockJsonWriter, value);

    // Should use runtimeTypeAdapter.write
    verify(mockRuntimeTypeAdapter).write(mockJsonWriter, value);
    verify(mockGson).getAdapter(TypeToken.get(runtimeType));
    verifyNoMoreInteractions(mockDelegateAdapter);
  }

  @Test
  void write_runtimeTypeDifferentRuntimeAdapterReflectiveDelegateNotReflective_usesDelegate() throws IOException {
    Object value = "string"; // runtimeType = String.class, declaredType = Object.class
    Type runtimeType = String.class;

    // Prepare a runtimeTypeAdapter which is instance of Adapter (ReflectiveTypeAdapterFactory.Adapter)
    TypeAdapter<Object> reflectiveRuntimeAdapter = mock(Adapter.class);

    when(mockGson.getAdapter(TypeToken.get(runtimeType))).thenReturn(reflectiveRuntimeAdapter);

    // Prepare delegate which is NOT instance of Adapter
    TypeAdapter<Object> nonReflectiveDelegate = mock(TypeAdapter.class);
    wrapper = new TypeAdapterRuntimeTypeWrapper<>(mockGson, nonReflectiveDelegate, declaredType);

    wrapper.write(mockJsonWriter, value);

    // Should use delegate.write
    verify(nonReflectiveDelegate).write(mockJsonWriter, value);
    verify(mockGson).getAdapter(TypeToken.get(runtimeType));
    verifyNoMoreInteractions(reflectiveRuntimeAdapter);
  }

  @Test
  void write_runtimeTypeDifferentRuntimeAdapterReflectiveDelegateReflective_usesRuntimeAdapter() throws IOException {
    Object value = "string"; // runtimeType = String.class, declaredType = Object.class
    Type runtimeType = String.class;

    // Prepare a runtimeTypeAdapter which is instance of Adapter (ReflectiveTypeAdapterFactory.Adapter)
    TypeAdapter<Object> reflectiveRuntimeAdapter = mock(Adapter.class);

    when(mockGson.getAdapter(TypeToken.get(runtimeType))).thenReturn(reflectiveRuntimeAdapter);

    // Prepare delegate which IS instance of Adapter
    TypeAdapter<Object> reflectiveDelegate = mock(Adapter.class);
    wrapper = new TypeAdapterRuntimeTypeWrapper<>(mockGson, reflectiveDelegate, declaredType);

    wrapper.write(mockJsonWriter, value);

    // Should use runtimeTypeAdapter.write
    verify(reflectiveRuntimeAdapter).write(mockJsonWriter, value);
    verify(mockGson).getAdapter(TypeToken.get(runtimeType));
    verifyNoMoreInteractions(reflectiveDelegate);
  }

  @Test
  void write_nullValue_usesDelegateWrite() throws IOException {
    Object value = null;

    // null value means runtimeType == declaredType (null check in getRuntimeTypeIfMoreSpecific)
    wrapper.write(mockJsonWriter, value);

    verify(mockDelegateAdapter).write(mockJsonWriter, null);
    verifyNoMoreInteractions(mockGson);
  }
}
